        <li className="nav-item mb-2"><a className="nav-link text-white" href="#">Assignments</a></li>
        <li className="nav-item mb-2"><a className="nav-link text-white" href="#">Calendar</a></li>
        <li className="nav-item mb-2"><a className="nav-link text-white" href="#">Export</a></li>
      </ul>
      <div className="mt-auto small">© College</div>
